// --- HELPER FUNCTIONS ---
export function getTeam(id: string): Team | undefined {
  return TEAMS.find(t => t.id === id);
}

export function getTeamPlayers(teamId: string): Player[] {
  return PLAYERS.filter(p => p.team === teamId);
}

export function getTeamMatches(teamId: string): Match[] {
  return MATCHES.filter(m => m.homeTeam === teamId || m.awayTeam === teamId);
}

export function getMatchweekMatches(week: number): Match[] {
  return MATCHES.filter(m => m.week === week);
}

export function calculateDistance(lat1: number, lng1: number, lat2: number, lng2: number): number {
  const R = 3959; // Earth radius in miles
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLng = (lng2 - lng1) * Math.PI / 180;
  const a = Math.sin(dLat / 2) ** 2 + Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) * Math.sin(dLng / 2) ** 2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

